import{_ as t,o as s,c as a,ag as i}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"How Suggestions Work","description":"","frontmatter":{},"headers":[],"relativePath":"training/suggestions.md","filePath":"training/suggestions.md"}'),r={name:"training/suggestions.md"};function n(o,e,g,d,l,h){return s(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="how-suggestions-work" tabindex="-1">How Suggestions Work <a class="header-anchor" href="#how-suggestions-work" aria-label="Permalink to &quot;How Suggestions Work&quot;">​</a></h1><p>The training suggestion engine continuously monitors player analytics against thresholds and surfaces issues that warrant attention.</p><h2 id="what-triggers-a-suggestion" tabindex="-1">What Triggers a Suggestion <a class="header-anchor" href="#what-triggers-a-suggestion" aria-label="Permalink to &quot;What Triggers a Suggestion&quot;">​</a></h2><p>Suggestions are generated when a metric falls below its configured threshold and the player has enough data for the stat to be meaningful. Examples:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Default Threshold</th><th>Priority</th></tr></thead><tbody><tr><td>Batting average below .200</td><td>20+ AB</td><td>High</td></tr><tr><td>Strike rate below 55%</td><td>30+ pitches</td><td>High</td></tr><tr><td>Walk rate above 15%</td><td>20+ PA</td><td>Medium</td></tr><tr><td>Fielding % below .850</td><td>15+ chances</td><td>Medium</td></tr><tr><td>Mechanics element below 1.5 average</td><td>3+ assessments</td><td>High</td></tr><tr><td>Stolen base % below 60%</td><td>5+ attempts</td><td>Low</td></tr></tbody></table><p>Thresholds are fully customizable per team through <strong>Settings → Analytics Settings</strong>.</p><h2 id="priority-levels" tabindex="-1">Priority Levels <a class="header-anchor" href="#priority-levels" aria-label="Permalink to &quot;Priority Levels&quot;">​</a></h2><p><strong>High</strong> — significant performance issue affecting game outcomes. Address immediately.</p><p><strong>Medium</strong> — developing issue that needs attention before it becomes a larger problem.</p><p><strong>Low</strong> — area for improvement that won&#39;t significantly affect game outcomes in the short term.</p><h2 id="suggestion-cards" tabindex="-1">Suggestion Cards <a class="header-anchor" href="#suggestion-cards" aria-label="Permalink to &quot;Suggestion Cards&quot;">​</a></h2><p>Each suggestion card shows:</p><ul><li>Player name and jersey number</li><li>The specific metric and current value</li><li>The threshold and how far below it the player is</li><li>A suggested focus area</li><li><strong>Create Training Plan</strong> button</li><li><strong>Find Drills</strong> button (opens YouTube drill search)</li><li><strong>Dismiss</strong> (X) button</li></ul><h2 id="when-suggestions-reappear" tabindex="-1">When Suggestions Reappear <a class="header-anchor" href="#when-suggestions-reappear" aria-label="Permalink to &quot;When Suggestions Reappear&quot;">​</a></h2><p>Dismissed suggestions come back after 30 days. They also come back earlier if the underlying metric declines by more than 10% since dismissal. This ensures that a genuinely improving issue does not keep resurging while a worsening problem always gets attention.</p><h2 id="suggestions-vs-coach-judgment" tabindex="-1">Suggestions vs Coach Judgment <a class="header-anchor" href="#suggestions-vs-coach-judgment" aria-label="Permalink to &quot;Suggestions vs Coach Judgment&quot;">​</a></h2><p>Suggestions are data-driven starting points, not directives. A coach may have context the analytics do not — a player recovering from an injury, a recent mechanics adjustment that just needs time to show up in results, or a player who is already working on a specific issue. Dismiss suggestions freely when they do not reflect your actual development priorities.</p>',17)])])}const m=t(r,[["render",n]]);export{c as __pageData,m as default};
